      const SPECIAL_TYPES = new Set(['Fire', 'Water', 'Grass', 'Electric', 'Psychic', 'Ice', 'Dragon', 'Dark']);

      class RNG {
        constructor(seed = Date.now() % 2147483647) {
          this.seed = seed;
        }
        next() {
          this.seed = this.seed * 48271 % 2147483647;
