        makePlaceholder(label, w = 96, h = 96, bg = '#6c8cff', fg = '#ffffff') {
          const c = document.createElement('canvas');
          c.width = w;
          c.height = h;
          const g = c.getContext('2d');
          g.fillStyle = bg;
          g.fillRect(0, 0, w, h);
          g.fillStyle = 'rgba(255,255,255,0.18)';
          for (let i = 0; i < 6; i++) {
            g.fillRect((i * 17) % w, 0, 8, h);
          }
          g.strokeStyle = 'rgba(0,0,0,0.35)';
          g.lineWidth = 4;
          g.strokeRect(2, 2, w - 4, h - 4);
          g.fillStyle = fg;
          g.font = `bold ${Math.max(10, Math.floor(w / 7))}px sans-serif`;
          g.textAlign = 'center';
          g.textBaseline = 'middle';
          g.fillText(label, w / 2, h / 2);
          return c;
        }

        loadImage(key, src, fallbackCanvas) {
          this.total++;
          return new Promise((resolve) => {
            const img = new Image();
            img.crossOrigin = 'anonymous';
            img.onload = () => {
              this.images.set(key, img);
              this.loaded++;
              resolve(img);
            };
            img.onerror = () => {
              this.images.set(key, fallbackCanvas || this.makePlaceholder(key.slice(0, 6).toUpperCase()));
              this.failed.add(key);
              this.loaded++;
              resolve(this.images.get(key));
            };
            img.src = src;
