        }

        async preload() {
          const tasks = [];

          const frontMon = (id) => `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/${id}.png`;
          const backMon = (id) => `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/back/${id}.png`;
          const emeraldMon = (id) => `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/versions/generation-iii/emerald/${id}.png`;

          tasks.push(this.loadImage('enemy-squirtle', frontMon(7), this.makePlaceholder('SQ', 96, 96, '#5c8fe0')));
          tasks.push(this.loadImage('enemy-torchic', frontMon(255), this.makePlaceholder('TC', 96, 96, '#ff9050')));
          tasks.push(this.loadImage('player-treecko-back', backMon(252), this.makePlaceholder('TR', 96, 96, '#67c667')));
          tasks.push(this.loadImage('player-treecko-front', frontMon(252), this.makePlaceholder('TR', 96, 96, '#67c667')));
          tasks.push(this.loadImage('player-sprite', emeraldMon(255), this.makePlaceholder('P1', 64, 64, '#4474db')));
          tasks.push(this.loadImage('npc-sprite', emeraldMon(258), this.makePlaceholder('RV', 64, 64, '#d06080')));

          await Promise.all(tasks);
          this.ready = true;
        }

        progress() {
          return this.total === 0 ? 0 : this.loaded / this.total;
        }

        get(key) {
          return this.images.get(key) || this.makePlaceholder('NA');
        }
      }

      class TextPrinter {
        constructor(speed = 26) {
          this.speed = speed;
          this.fullText = '';
          this.visible = '';
          this.timer = 0;
          this.done = true;
        }
        set(text) {
          this.fullText = text || '';
          this.visible = '';
          this.timer = 0;
          this.done = this.fullText.length === 0;
        }
        update(dt) {
          if (this.done) return;
          this.timer += dt;
          const chars = Math.floor(this.timer / this.speed);
          if (chars > this.visible.length) {
            this.visible = this.fullText.slice(0, chars);
            if (this.visible.length >= this.fullText.length) {
              this.visible = this.fullText;
              this.done = true;
            }
          }
        }
        skip() {
          this.visible = this.fullText;
          this.done = true;
        }
      }

      function drawRoundedRect(ctx, x, y, w, h, r, fill, stroke, lineWidth = 2) {
        ctx.beginPath();
        ctx.moveTo(x + r, y);
        ctx.arcTo(x + w, y, x + w, y + h, r);
        ctx.arcTo(x + w, y + h, x, y + h, r);
        ctx.arcTo(x, y + h, x, y, r);
        ctx.arcTo(x, y, x + w, y, r);
        if (fill) {
          ctx.fillStyle = fill;
          ctx.fill();
        }
        if (stroke) {
          ctx.strokeStyle = stroke;
          ctx.lineWidth = lineWidth;
          ctx.stroke();
        }
      }

      function drawTextBox(ctx, x, y, w, h) {
        drawRoundedRect(ctx, x, y, w, h, 14, '#f8f8ff', '#1e2f78', 5);
        drawRoundedRect(ctx, x + 7, y + 7, w - 14, h - 14, 10, '#ffffff', '#8ca0f0', 3);
      }

      function wrapText(ctx, text, maxWidth) {
        const words = text.split(' ');
        const lines = [];
        let line = '';
        for (const word of words) {
          const test = line ? `${line} ${word}` : word;
          if (ctx.measureText(test).width > maxWidth && line) {
            lines.push(line);
            line = word;
          } else {
            line = test;
          }
        }
        if (line) lines.push(line);
        return lines;
      }

      function getTypeEffectiveness(moveType, targetTypes) {
        let multiplier = 1;
        for (const type of targetTypes) {
          const row = TYPE_CHART[moveType] || {};
          multiplier *= row[type] ?? 1;
        }
        return multiplier;
      }

      function moveCategory(type) {
        return SPECIAL_TYPES.has(type) ? 'Special' : 'Physical';
      }

      function clamp(v, min, max) {
        return Math.max(min, Math.min(max, v));
      }

      function lerp(a, b, t) {
        return a + (b - a) * t;
      }

      function createPokemon(data, assetManager, isPlayer = false) {
        const cloneMoves = data.moves.map(m => ({ ...m }));
        return {
          id: data.id,
          name: data.name,
          level: data.level,
          types: [...data.types],
          maxHp: data.stats.hp,
          hp: data.stats.hp,
          displayedHp: data.stats.hp,
          stats: { ...data.stats },
          moves: cloneMoves,
          spriteKey: isPlayer ? data.backSpriteKey : data.frontSpriteKey,
          frontSprite: assetManager.get(data.frontSpriteKey),
          backSprite: assetManager.get(data.backSpriteKey),
          cryPitch: rng.range(0.95, 1.05),
        };
      }

      class MapEngine {
        constructor(game) {
          this.game = game;
          this.tileSize = CONFIG.tileSize;
          this.map = [
            'TTTTTTTTTTTTTTTTTTTT',
            'TGGGGGGGGGGGGGGGGGGT',
            'TGGRRRRRRGGGGGGGGGGT',
            'TGGGRGGGRGGGGWWWWGGT',
            'TGGGRGGGRGGGGWWWWGGT',
            'TGGGRGGGRGGGGGGGGGGT',
            'TGGGRRRRRGGGGGGGGGGT',
            'TGGGGGGGGGGGRRRRGGGT',
            'TGGGGGTTGGGGRGGRGGGT',
            'TGGGGGTTGGGGRNGRGGGT',
            'TGGGGGGGGGGGRRRRGGGT',
            'TTTTTTTTTTTTTTTTTTTT',
          ];
          this.player = {
            tileX: 4,
            tileY: 6,
            fromX: 4,
            fromY: 6,
            toX: 4,
            toY: 6,
            px: 4 * this.tileSize,
            py: 6 * this.tileSize,
            moving: false,
            moveTimer: 0,
            dir: 'down',
            stepFrame: 0,
          };
          this.npc = {
            tileX: 13,
            tileY: 9,
            dir: 'left',
