          };
          this.dialogActive = false;
          this.dialogQueue = [];
          this.dialogPrinter = new TextPrinter(CONFIG.textSpeed);
          this.awaitingDialogAdvance = false;
          this.dialogDoneCallback = null;
          this.encounterTriggered = false;
          this.camera = { x: 0, y: 0 };
        }

        isWalkable(x, y) {
          if (y < 0 || y >= this.map.length || x < 0 || x >= this.map[0].length) return false;
          const tile = this.map[y][x];
          if (tile === 'T' || tile === 'W') return false;
          if (x === this.npc.tileX && y === this.npc.tileY) return false;
          return true;
        }

        tryMove(dx, dy) {
          const p = this.player;
          if (p.moving || this.dialogActive || this.game.state !== 'map') return;
          const nx = p.tileX + dx;
          const ny = p.tileY + dy;
          if (!this.isWalkable(nx, ny)) return;
          p.fromX = p.tileX;
          p.fromY = p.tileY;
          p.toX = nx;
          p.toY = ny;
          p.tileX = nx;
          p.tileY = ny;
          p.moveTimer = 0;
          p.moving = true;
          p.stepFrame = (p.stepFrame + 1) % 2;
          if (dx > 0) p.dir = 'right';
          else if (dx < 0) p.dir = 'left';
          else if (dy > 0) p.dir = 'down';
          else if (dy < 0) p.dir = 'up';
        }

        isPlayerFacingNpc() {
          const p = this.player;
          const delta = {
            up: [0, -1],
            down: [0, 1],
            left: [-1, 0],
            right: [1, 0],
          }[p.dir];
          const tx = p.tileX + delta[0];
          const ty = p.tileY + delta[1];
          return tx === this.npc.tileX && ty === this.npc.tileY;
        }

        startDialog(lines, onDone) {
          this.dialogActive = true;
          this.dialogQueue = [...lines];
          this.dialogDoneCallback = onDone || null;
          this.nextDialogLine();
        }

        nextDialogLine() {
          if (this.dialogQueue.length === 0) {
            this.dialogActive = false;
            const cb = this.dialogDoneCallback;
            this.dialogDoneCallback = null;
            if (cb) cb();
            return;
          }
          const line = this.dialogQueue.shift();
          this.dialogPrinter.set(line);
          this.awaitingDialogAdvance = false;
        }

        update(dt, input) {
          if (this.dialogActive) {
            this.dialogPrinter.update(dt);
            if (input.consumeAny(['z', 'enter', ' '])) {
              if (!this.dialogPrinter.done) this.dialogPrinter.skip();
              else this.nextDialogLine();
            }
            return;
          }

          const p = this.player;
          if (p.moving) {
            p.moveTimer += dt;
            const t = clamp(p.moveTimer / CONFIG.moveDuration, 0, 1);
            p.px = lerp(p.fromX * this.tileSize, p.toX * this.tileSize, t);
            p.py = lerp(p.fromY * this.tileSize, p.toY * this.tileSize, t);
