              `${this.npc.name} challenged you to a battle!`
            ], () => {
              this.game.startBattleTransition();
            });
          }

          this.camera.x = clamp((p.px + this.tileSize / 2) - CONFIG.width / 2, 0, this.map[0].length * this.tileSize - CONFIG.width);
          this.camera.y = clamp((p.py + this.tileSize / 2) - CONFIG.height / 2, 0, this.map.length * this.tileSize - CONFIG.height);
          this.game.setHint(this.isPlayerFacingNpc() && !this.encounterTriggered ? 'Press Z to talk' : 'Arrow Keys: Move · Z: Interact');
        }

        drawTile(x, y, tile) {
          const sx = x * this.tileSize - this.camera.x;
          const sy = y * this.tileSize - this.camera.y;
          const s = this.tileSize;
          if (tile === 'G' || tile === 'N') {
            ctx.fillStyle = ((x + y) % 2 === 0) ? '#4fb54d' : '#45a443';
            ctx.fillRect(sx, sy, s, s);
            ctx.fillStyle = 'rgba(255,255,255,0.08)';
            for (let i = 0; i < 5; i++) {
              ctx.fillRect(sx + 4 + i * 8, sy + 10 + (i % 2) * 8, 2, 8);
            }
          } else if (tile === 'R') {
            ctx.fillStyle = ((x + y) % 2 === 0) ? '#c5aa74' : '#b5945f';
            ctx.fillRect(sx, sy, s, s);
            ctx.fillStyle = 'rgba(255,255,255,0.12)';
            ctx.fillRect(sx, sy + s - 10, s, 4);
          } else if (tile === 'T') {
            ctx.fillStyle = '#2f7b35';
            ctx.fillRect(sx, sy, s, s);
            ctx.fillStyle = '#1d5324';
            ctx.beginPath();
            ctx.arc(sx + s * 0.5, sy + s * 0.38, s * 0.28, 0, Math.PI * 2);
            ctx.arc(sx + s * 0.35, sy + s * 0.48, s * 0.22, 0, Math.PI * 2);
            ctx.arc(sx + s * 0.65, sy + s * 0.48, s * 0.22, 0, Math.PI * 2);
            ctx.fill();
            ctx.fillStyle = '#795339';
            ctx.fillRect(sx + s * 0.44, sy + s * 0.54, s * 0.12, s * 0.28);
          } else if (tile === 'W') {
            ctx.fillStyle = ((x + y) % 2 === 0) ? '#5ba6ff' : '#468ddd';
            ctx.fillRect(sx, sy, s, s);
            ctx.strokeStyle = 'rgba(255,255,255,0.3)';
            ctx.beginPath();
            ctx.moveTo(sx + 4, sy + 12);
            ctx.lineTo(sx + s - 4, sy + 12);
            ctx.moveTo(sx + 6, sy + 28);
            ctx.lineTo(sx + s - 6, sy + 28);
            ctx.stroke();
          }

          if (tile === 'N') {
            ctx.fillStyle = '#fff4ad';
            ctx.fillRect(sx + 10, sy + 10, s - 20, s - 20);
            ctx.strokeStyle = '#7a6130';
            ctx.lineWidth = 3;
            ctx.strokeRect(sx + 10, sy + 10, s - 20, s - 20);
          }
        }

        drawCharacter(spriteImg, x, y, dir, isNpc = false) {
          const sx = x - this.camera.x;
          const sy = y - this.camera.y;
          const w = this.tileSize;
          const h = this.tileSize + 12;

          ctx.save();
          ctx.translate(sx + w / 2, sy + this.tileSize / 2);
          const bob = isNpc ? 0 : (this.player.moving ? (this.player.stepFrame === 0 ? -1 : 1) * 2 : 0);
          ctx.translate(0, bob);

          ctx.fillStyle = 'rgba(0,0,0,0.22)';
          ctx.beginPath();
          ctx.ellipse(0, 16, 12, 6, 0, 0, Math.PI * 2);
          ctx.fill();

          if (spriteImg && spriteImg.width > 1) {
            const scale = 1.5;
            ctx.drawImage(spriteImg, -spriteImg.width * scale / 2, -spriteImg.height * scale / 2 - 6, spriteImg.width * scale, spriteImg.height * scale);
          } else {
            ctx.fillStyle = isNpc ? '#d96d84' : '#4f7cff';
            ctx.fillRect(-12, -22, 24, 28);
            ctx.fillStyle = '#ffe0c0';
            ctx.fillRect(-10, -28, 20, 12);
          }

          if (!spriteImg || spriteImg.width <= 1) {
            ctx.fillStyle = '#1b1b1b';
            if (dir === 'left') ctx.fillRect(-10, -16, 4, 4);
            if (dir === 'right') ctx.fillRect(6, -16, 4, 4);
            if (dir === 'up') { ctx.fillRect(-7, -16, 4, 4); ctx.fillRect(3, -16, 4, 4); }
            if (dir === 'down') { ctx.fillRect(-5, -14, 10, 2); }
          }
          ctx.restore();
        }

        render() {
          ctx.fillStyle = '#4aa0ef';
          ctx.fillRect(0, 0, CONFIG.width, CONFIG.height);

          for (let y = 0; y < this.map.length; y++) {
            for (let x = 0; x < this.map[y].length; x++) {
              this.drawTile(x, y, this.map[y][x]);
            }
          }

          this.drawCharacter(this.game.assets.get('npc-sprite'), this.npc.tileX * this.tileSize, this.npc.tileY * this.tileSize - 6, this.npc.dir, true);
          this.drawCharacter(this.game.assets.get('player-sprite'), this.player.px, this.player.py - 6, this.player.dir, false);

          if (this.dialogActive) {
            this.renderDialog();
          }
        }

        renderDialog() {
          const x = 48;
          const y = CONFIG.height - 150;
          const w = CONFIG.width - 96;
          const h = 110;
          drawTextBox(ctx, x, y, w, h);
          ctx.fillStyle = '#1c2450';
          ctx.font = '24px "Trebuchet MS", sans-serif';
          const lines = wrapText(ctx, this.dialogPrinter.visible, w - 48);
          lines.slice(0, 3).forEach((line, i) => {
            ctx.fillText(line, x + 24, y + 38 + i * 28);
          });
          if (this.dialogPrinter.done) {
            ctx.fillStyle = '#4a69d9';
            ctx.beginPath();
            ctx.moveTo(x + w - 28, y + h - 28);
            ctx.lineTo(x + w - 14, y + h - 28);
            ctx.lineTo(x + w - 21, y + h - 16);
            ctx.closePath();
            ctx.fill();
          }
        }
      }

      class BattleEngine {
        constructor(game) {
          this.game = game;
          this.player = null;
          this.enemy = null;
          this.state = 'idle';
          this.textPrinter = new TextPrinter(CONFIG.textSpeed);
          this.messageQueue = [];
          this.menuIndex = 0;
          this.moveIndex = 0;
          this.activeMenu = 'root';
          this.anim = {
            timer: 0,
            attackerShake: 0,
            targetShake: 0,
            flash: 0,
            impact: 0,
          };
          this.turnOwner = 'player';
          this.pendingAction = null;
          this.endTimer = 0;
          this.lastActionSummary = '';
        }

        setupBattle() {
          this.player = createPokemon({
            id: 252,
            name: 'TREECKO',
            level: 15,
            types: ['Grass'],
            stats: { hp: 44, attack: 28, defense: 24, spAttack: 27, spDefense: 26, speed: 32 },
            moves: [
              { name: 'Pound', type: 'Normal', power: 40, accuracy: 1 },
              { name: 'Absorb', type: 'Grass', power: 20, accuracy: 1 },
              { name: 'Quick Attack', type: 'Normal', power: 40, accuracy: 1 },
              { name: 'Pursuit', type: 'Dark', power: 40, accuracy: 1 },
            ],
            frontSpriteKey: 'player-treecko-front',
            backSpriteKey: 'player-treecko-back',
          }, this.game.assets, true);

          this.enemy = createPokemon({
            id: 7,
            name: 'SQUIRTLE',
            level: 15,
            types: ['Water'],
            stats: { hp: 46, attack: 25, defense: 30, spAttack: 25, spDefense: 28, speed: 22 },
            moves: [
              { name: 'Tackle', type: 'Normal', power: 40, accuracy: 1 },
              { name: 'Water Gun', type: 'Water', power: 40, accuracy: 1 },
              { name: 'Bite', type: 'Dark', power: 60, accuracy: 1 },
              { name: 'Tail Whip', type: 'Normal', power: 0, accuracy: 1, status: 'none' },
            ],
            frontSpriteKey: 'enemy-squirtle',
            backSpriteKey: 'enemy-torchic',
          }, this.game.assets, false);

          this.player.displayedHp = this.player.hp;
          this.enemy.displayedHp = this.enemy.hp;
          this.menuIndex = 0;
          this.moveIndex = 0;
          this.activeMenu = 'root';
          this.anim.timer = 0;
          this.messageQueue = [];
          this.state = 'intro';
          this.queueMessage('Rival May sent out SQUIRTLE!');
          this.queueMessage('Go! TREECKO!');
        }

        queueMessage(msg) {
          this.messageQueue.push(msg);
          if (this.textPrinter.done && this.state !== 'animating') {
            this.showNextMessage();
          }
        }

        showNextMessage() {
          if (this.messageQueue.length > 0) {
            this.textPrinter.set(this.messageQueue.shift());
            this.state = 'message';
          } else if (this.player.hp <= 0 || this.enemy.hp <= 0) {
            this.state = 'end';
            this.endTimer = 1400;
          } else {
            this.state = 'command';
            this.activeMenu = 'root';
          }
        }

        update(dt, input) {
          this.player.displayedHp = lerp(this.player.displayedHp, this.player.hp, CONFIG.hpLerpSpeed);
          this.enemy.displayedHp = lerp(this.enemy.displayedHp, this.enemy.hp, CONFIG.hpLerpSpeed);
          if (Math.abs(this.player.displayedHp - this.player.hp) < 0.05) this.player.displayedHp = this.player.hp;
          if (Math.abs(this.enemy.displayedHp - this.enemy.hp) < 0.05) this.enemy.displayedHp = this.enemy.hp;

          this.textPrinter.update(dt);
          this.anim.timer = Math.max(0, this.anim.timer - dt);
          this.anim.flash = Math.max(0, this.anim.flash - dt / 220);
          this.anim.impact = Math.max(0, this.anim.impact - dt / 220);

          if (this.state === 'message') {
            if (input.consumeAny(['z', 'enter', ' '])) {
              if (!this.textPrinter.done) this.textPrinter.skip();
              else this.showNextMessage();
            }
            return;
          }

          if (this.state === 'command') {
            this.handleCommandInput(input);
            return;
          }

          if (this.state === 'animating') {
            if (this.anim.timer <= 0) {
              const fn = this.pendingAction;
              this.pendingAction = null;
              if (fn) fn();
            }
            return;
          }

          if (this.state === 'end') {
            this.endTimer -= dt;
            if (this.endTimer <= 0) {
              this.game.returnToMapAfterBattle(this.player.hp > 0);
            }
          }
        }

        handleCommandInput(input) {
          if (this.activeMenu === 'root') {
            if (input.consume('arrowright') || input.consume('arrowdown')) this.menuIndex = (this.menuIndex + 1) % 3;
            if (input.consume('arrowleft') || input.consume('arrowup')) this.menuIndex = (this.menuIndex + 2) % 3;
            if (input.consumeAny(['z', 'enter', ' '])) {
              if (this.menuIndex === 0) {
                this.activeMenu = 'fight';
                this.moveIndex = 0;
              } else if (this.menuIndex === 1) {
                this.queueMessage('The BAG is packed too tightly to use right now.');
              } else {
                this.queueMessage('No running from a rival battle!');
              }
            }
          } else if (this.activeMenu === 'fight') {
            if (input.consume('arrowup')) this.moveIndex = (this.moveIndex + 3) % 4;
            if (input.consume('arrowdown')) this.moveIndex = (this.moveIndex + 1) % 4;
            if (input.consume('arrowleft')) this.moveIndex = (this.moveIndex + 2) % 4;
            if (input.consume('arrowright')) this.moveIndex = (this.moveIndex + 2) % 4;
            if (input.consume('x')) this.activeMenu = 'root';
            if (input.consumeAny(['z', 'enter', ' '])) {
              const selected = this.player.moves[this.moveIndex];
              this.performTurn(selected);
            }
          }
        }

        performTurn(playerMove) {
          const enemyMove = this.chooseEnemyMove();
          const playerFirst = this.player.stats.speed >= this.enemy.stats.speed;
          const order = playerFirst
            ? [
                { side: 'player', move: playerMove, user: this.player, target: this.enemy },
                { side: 'enemy', move: enemyMove, user: this.enemy, target: this.player }
              ]
            : [
                { side: 'enemy', move: enemyMove, user: this.enemy, target: this.player },
                { side: 'player', move: playerMove, user: this.player, target: this.enemy }
              ];
          this.activeMenu = 'root';
          this.menuIndex = 0;
          this.resolveActionSequence(order, 0);
        }

        resolveActionSequence(order, index) {
          if (index >= order.length) {
            this.showNextMessage();
            return;
          }
          const action = order[index];
          if (action.user.hp <= 0 || action.target.hp <= 0) {
            this.resolveActionSequence(order, index + 1);
            return;
          }

          this.queueMessage(`${action.side === 'player' ? this.player.name : 'Foe ' + this.enemy.name} used ${action.move.name}!`);
          const result = this.computeMove(action.user, action.target, action.move);
          this.state = 'animating';
          this.anim.timer = 420;
          this.anim.flash = 1;
          this.pendingAction = () => {
            if (action.side === 'player') this.anim.targetShake = 1; else this.anim.targetShake = -1;
            if (result.hit && result.damage > 0) {
              action.target.hp = clamp(action.target.hp - result.damage, 0, action.target.maxHp);
              this.anim.impact = 1;
            }

            if (!result.hit) this.queueMessage('But it missed!');
            else if (action.move.power === 0) this.queueMessage('But nothing happened!');
            else {
              if (result.critical) this.queueMessage('A critical hit!');
              if (result.effectiveness > 1) this.queueMessage("It's super effective!");
              if (result.effectiveness > 0 && result.effectiveness < 1) this.queueMessage("It's not very effective...");
              if (result.effectiveness === 0) this.queueMessage("It doesn't affect the target...");
              if (action.move.name === 'Absorb' && result.damage > 0) {
                const heal = Math.max(1, Math.floor(result.damage / 2));
                action.user.hp = clamp(action.user.hp + heal, 0, action.user.maxHp);
                this.queueMessage(`${action.user.name} absorbed health!`);
              }
            }

            if (action.target.hp <= 0) {
              this.queueMessage(`${action.target === this.enemy ? 'Foe ' + this.enemy.name : this.player.name} fainted!`);
            }
            this.state = 'message';
            this.showNextMessage();
            if (action.target.hp <= 0) return;
            this.resolveActionSequence(order, index + 1);
          };
        }

        chooseEnemyMove() {
          const moves = this.enemy.moves;
          let bestMove = moves[0];
          let bestScore = -Infinity;

          for (const move of moves) {
            let score = 0;
            const effect = getTypeEffectiveness(move.type, this.player.types);
            const sim = this.computeMove(this.enemy, this.player, move, true);
            if (sim.damage >= this.player.hp) score += 1000;
            if (effect > 1) score += 200;
            if (effect === 0) score -= 100;
            if (move.power === 0) score -= 50;
            score += sim.damage;
            score += rng.range(0, 4);
            if (score > bestScore) {
              bestScore = score;
              bestMove = move;
            }
          }

          if (!bestMove) bestMove = moves.find(m => m.power > 0) || moves[0];
          return bestMove;
        }

        computeMove(attacker, defender, move, silent = false) {
          if (move.power === 0) {
            return { hit: true, damage: 0, effectiveness: 1, critical: false };
          }

          const hit = rng.next() <= (move.accuracy ?? 1);
          if (!hit) return { hit: false, damage: 0, effectiveness: 1, critical: false };

          const category = moveCategory(move.type);
          const A = category === 'Special' ? attacker.stats.spAttack : attacker.stats.attack;
          const D = category === 'Special' ? defender.stats.spDefense : defender.stats.defense;
          const base = (((2 * attacker.level / 5 + 2) * move.power * A / D) / 50) + 2;
          const critical = rng.chance(1 / 16);
          const stab = attacker.types.includes(move.type) ? 1.5 : 1;
          const effectiveness = getTypeEffectiveness(move.type, defender.types);
          const modifier = (critical ? 2 : 1) * stab * effectiveness * rng.range(0.92, 1.0);
          const damage = effectiveness === 0 ? 0 : Math.max(1, Math.floor(base * modifier));
          return { hit: true, damage, effectiveness, critical, category };
        }

        hpColor(ratio) {
          if (ratio > 0.5) return '#70d050';
          if (ratio > 0.2) return '#e0c040';
          return '#d85858';
        }

        drawStatusBox(x, y, w, h, mon, isEnemy) {
          ctx.save();
          ctx.translate(x, y);
          ctx.fillStyle = '#f8f8f0';
          ctx.strokeStyle = '#364059';
          ctx.lineWidth = 3;
          ctx.beginPath();
          ctx.moveTo(0, 8);
          ctx.lineTo(w - 20, 0);
          ctx.lineTo(w, 10);
          ctx.lineTo(w, h - 12);
          ctx.lineTo(20, h);
          ctx.lineTo(0, h - 8);
          ctx.closePath();
          ctx.fill();
          ctx.stroke();

          ctx.fillStyle = '#1f2430';
          ctx.font = 'bold 24px Trebuchet MS';
          ctx.fillText(mon.name, 16, 30);
          ctx.font = '18px Trebuchet MS';
          ctx.fillText(`Lv${mon.level}`, w - 68, 30);
          ctx.fillStyle = '#686868';
          ctx.font = 'bold 14px Trebuchet MS';
          ctx.fillText('HP', 24, 56);

          const barX = 54;
          const barY = 44;
          const barW = w - 88;
          const barH = 14;
          ctx.fillStyle = '#304040';
          ctx.fillRect(barX, barY, barW, barH);
          const ratio = clamp(mon.displayedHp / mon.maxHp, 0, 1);
          ctx.fillStyle = this.hpColor(ratio);
          ctx.fillRect(barX + 2, barY + 2, Math.max(0, (barW - 4) * ratio), barH - 4);
          ctx.strokeStyle = '#101010';
          ctx.strokeRect(barX, barY, barW, barH);

          if (!isEnemy) {
            ctx.fillStyle = '#303030';
            ctx.font = '18px Courier New';
            ctx.fillText(`${Math.ceil(mon.displayedHp)} / ${mon.maxHp}`, w - 118, h - 12);
          }
          ctx.restore();
        }

        renderBattleBg() {
          const grad = ctx.createLinearGradient(0, 0, 0, CONFIG.height);
          grad.addColorStop(0, '#9fdbff');
          grad.addColorStop(0.62, '#c6ebff');
          grad.addColorStop(0.63, '#f0e7be');
          grad.addColorStop(1, '#d4c378');
          ctx.fillStyle = grad;
          ctx.fillRect(0, 0, CONFIG.width, CONFIG.height);

          ctx.fillStyle = 'rgba(255,255,255,0.26)';
          ctx.beginPath();
          ctx.ellipse(180, 90, 200, 40, 0, 0, Math.PI * 2);
          ctx.fill();
          ctx.beginPath();
          ctx.ellipse(730, 150, 170, 36, 0, 0, Math.PI * 2);
          ctx.fill();

          ctx.fillStyle = '#8dcf75';
          ctx.beginPath();
          ctx.ellipse(250, 430, 180, 42, 0, 0, Math.PI * 2);
          ctx.fill();

          ctx.fillStyle = '#86c46f';
          ctx.beginPath();
          ctx.ellipse(720, 270, 140, 34, 0, 0, Math.PI * 2);
          ctx.fill();

          ctx.fillStyle = 'rgba(0,0,0,0.08)';
          ctx.beginPath();
          ctx.ellipse(250, 442, 160, 26, 0, 0, Math.PI * 2);
          ctx.fill();
          ctx.beginPath();
          ctx.ellipse(720, 282, 120, 22, 0, 0, Math.PI * 2);
          ctx.fill();
        }

        renderSprites() {
          const shakeX = (this.anim.impact > 0 ? rng.range(-4, 4) : 0);
          ctx.save();
          if (this.anim.flash > 0) {
            ctx.globalAlpha = 1 - this.anim.flash * 0.35;
          }

          const enemyX = 660 + shakeX;
          const enemyY = 238 + (this.anim.impact > 0 ? rng.range(-5, 5) : 0);
          const enemyImg = this.enemy.frontSprite;
          if (enemyImg) ctx.drawImage(enemyImg, enemyX - 96, enemyY - 96, 192, 192);

          const playerX = 250;
          const playerY = 425;
          const playerImg = this.player.backSprite;
          if (playerImg) ctx.drawImage(playerImg, playerX - 130, playerY - 130, 230, 230);
          ctx.restore();
        }

        renderPanel() {
          drawTextBox(ctx, 22, CONFIG.height - 184, CONFIG.width - 44, 162);
          if (this.state === 'command' && this.activeMenu === 'root') {
            ctx.fillStyle = '#1e2a4e';
            ctx.font = '26px Trebuchet MS';
            ctx.fillText('What will TREECKO do?', 48, CONFIG.height - 132);
            const options = ['FIGHT', 'BAG', 'RUN'];
            options.forEach((opt, i) => {
              const col = i % 2;
              const row = Math.floor(i / 2);
              const x = 560 + col * 160;
              const y = CONFIG.height - 138 + row * 52;
              drawRoundedRect(ctx, x, y, 132, 40, 10, i === this.menuIndex ? '#ffd95a' : '#f4f7ff', '#2f47ab', 3);
              ctx.fillStyle = '#1f2430';
              ctx.font = 'bold 22px Trebuchet MS';
              ctx.fillText(opt, x + 28, y + 27);
            });
          } else if (this.state === 'command' && this.activeMenu === 'fight') {
            ctx.fillStyle = '#1e2a4e';
            ctx.font = '24px Trebuchet MS';
            ctx.fillText('Choose a move', 48, CONFIG.height - 136);
            this.player.moves.forEach((move, i) => {
              const col = i % 2;
              const row = Math.floor(i / 2);
              const x = 48 + col * 240;
              const y = CONFIG.height - 112 + row * 42;
              drawRoundedRect(ctx, x, y, 210, 34, 8, i === this.moveIndex ? '#ffd95a' : '#f8fbff', '#2f47ab', 3);
              ctx.fillStyle = '#1d2440';
              ctx.font = '20px Trebuchet MS';
              ctx.fillText(move.name, x + 16, y + 23);
            });
            const move = this.player.moves[this.moveIndex];
            ctx.font = '18px Trebuchet MS';
            ctx.fillStyle = '#24315a';
            ctx.fillText(`TYPE/${move.type}`, 560, CONFIG.height - 112);
            ctx.fillText(`CAT/${moveCategory(move.type).toUpperCase()}`, 560, CONFIG.height - 82);
            ctx.fillText(`PWR/${move.power}`, 560, CONFIG.height - 52);
            ctx.fillText('X: Back', 760, CONFIG.height - 52);
          } else {
            ctx.fillStyle = '#1c2450';
            ctx.font = '24px Trebuchet MS';
            const lines = wrapText(ctx, this.textPrinter.visible, CONFIG.width - 110);
            lines.slice(0, 3).forEach((line, i) => ctx.fillText(line, 50, CONFIG.height - 132 + i * 30));
            if (this.textPrinter.done && this.state === 'message') {
              ctx.fillStyle = '#4a69d9';
              ctx.beginPath();
              ctx.moveTo(CONFIG.width - 60, CONFIG.height - 48);
              ctx.lineTo(CONFIG.width - 42, CONFIG.height - 48);
              ctx.lineTo(CONFIG.width - 51, CONFIG.height - 30);
              ctx.closePath();
              ctx.fill();
            }
          }
        }

        render() {
          this.renderBattleBg();
          this.drawStatusBox(560, 70, 320, 90, this.enemy, true);
          this.drawStatusBox(70, 330, 360, 100, this.player, false);
          this.renderSprites();
          this.renderPanel();

          if (this.state === 'end') {
            const alpha = clamp(1 - this.endTimer / 1400, 0, 0.5);
            ctx.fillStyle = `rgba(0,0,0,${alpha})`;
            ctx.fillRect(0, 0, CONFIG.width, CONFIG.height);
          }
        }
      }

      class TransitionEffect {
        constructor() {
          this.active = false;
          this.timer = 0;
          this.duration = 1350;
          this.done = false;
        }
        start() {
          this.active = true;
          this.timer = 0;
          this.done = false;
        }
        update(dt) {
          if (!this.active) return;
          this.timer += dt;
          if (this.timer >= this.duration) {
            this.active = false;
            this.done = true;
          }
        }
        render(ctx) {
          if (!this.active) return;
          const p = clamp(this.timer / this.duration, 0, 1);
          const flash = Math.sin(p * Math.PI * 6) * (1 - p);
          if (flash > 0) {
            ctx.fillStyle = `rgba(255,255,255,${flash * 0.75})`;
            ctx.fillRect(0, 0, CONFIG.width, CONFIG.height);
          }

          const ringCount = 12;
          ctx.save();
          ctx.translate(CONFIG.width / 2, CONFIG.height / 2);
          for (let i = 0; i < ringCount; i++) {
            const angle = (i / ringCount) * Math.PI * 2 + p * 16;
            const dist = lerp(40, 540, p);
            const x = Math.cos(angle) * dist * 0.9;
            const y = Math.sin(angle) * dist * 0.55;
            const size = lerp(10, 80, p);
            ctx.fillStyle = `rgba(0,0,0,${0.10 + p * 0.42})`;
            ctx.fillRect(x - size / 2, y - size / 2, size, size);
          }
          ctx.restore();

          const mosaic = Math.max(1, Math.floor(1 + p * 24));
          ctx.fillStyle = `rgba(0,0,0,${p * 0.72})`;
          for (let y = 0; y < CONFIG.height; y += mosaic * 2) {
            for (let x = 0; x < CONFIG.width; x += mosaic * 2) {
              if (((x + y) / (mosaic * 2)) % 2 < 1) {
                ctx.fillRect(x, y, mosaic * 2, mosaic * 2);
              }
            }
          }

          if (p > 0.65) {
            ctx.fillStyle = `rgba(0,0,0,${(p - 0.65) / 0.35})`;
            ctx.fillRect(0, 0, CONFIG.width, CONFIG.height);
          }
        }
      }

      class Game {
        constructor() {
          this.assets = new AssetManager();
          this.input = new InputManager();
          this.mapEngine = new MapEngine(this);
          this.battleEngine = new BattleEngine(this);
          this.transition = new TransitionEffect();
          this.state = 'loading';
          this.lastTime = performance.now();
          this.readyToStart = false;
          this.hintText = '';
          this.hintTimer = 0;
          this.startGame = false;
        }

        async init() {
          loadingTitle.textContent = 'Loading...';
          loadingSub.textContent = 'Preparing map, sprites, and battle scene';

          const preloadPromise = this.assets.preload();
          const interval = setInterval(() => {
            const p = this.assets.progress();
            loadingFill.style.width = `${Math.floor(p * 100)}%`;
          }, 50);

          await preloadPromise;
          clearInterval(interval);
          loadingFill.style.width = '100%';
          loadingTitle.textContent = 'Ready';
          loadingSub.textContent = 'Assets loaded. Press any key to start.';
          startPrompt.classList.add('ready');
          this.readyToStart = true;
          requestAnimationFrame(this.loop.bind(this));
        }

        setHint(text) {
          if (text !== this.hintText) {
            this.hintText = text;
            hintPill.textContent = text;
            hintPill.classList.add('show');
          }
        }

        startBattleTransition() {
          this.state = 'transition';
          this.transition.start();
        }

        enterBattle() {
          this.battleEngine.setupBattle();
          this.state = 'battle';
        }

        returnToMapAfterBattle(victory) {
          this.state = 'map';
          this.mapEngine.startDialog([
            victory
              ? 'Rival May: Nice! Your moves were really sharp!'
              : 'Rival May: You still need more training!'
          ], () => {
            this.setHint('Battle complete · Refresh to play again');
          });
        }

        update(dt) {
          if (this.readyToStart && !this.startGame) {
            if (this.input.startPressed) {
              this.startGame = true;
              this.state = 'map';
              loadingOverlay.style.display = 'none';
              this.setHint('Arrow Keys: Move · Z: Interact');
            }
            return;
          }

          if (this.state === 'map') {
            this.mapEngine.update(dt, this.input);
          } else if (this.state === 'transition') {
            this.transition.update(dt);
            if (this.transition.done) {
              this.transition.done = false;
              this.enterBattle();
            }
          } else if (this.state === 'battle') {
            this.battleEngine.update(dt, this.input);
          }
        }

        render() {
          ctx.clearRect(0, 0, CONFIG.width, CONFIG.height);
          if (!this.startGame) {
            ctx.fillStyle = '#0c1328';
            ctx.fillRect(0, 0, CONFIG.width, CONFIG.height);
            ctx.fillStyle = '#d4e7ff';
            ctx.font = 'bold 52px Trebuchet MS';
            ctx.textAlign = 'center';
            ctx.fillText('Pokémon Battle Demo', CONFIG.width / 2, 180);
            ctx.font = '28px Trebuchet MS';
            ctx.fillStyle = '#fff8bf';
            ctx.fillText('Gen 3 style map → dialog → battle', CONFIG.width / 2, 228);
            ctx.textAlign = 'left';
            return;
          }

          if (this.state === 'map' || this.state === 'transition') {
            this.mapEngine.render();
          } else if (this.state === 'battle') {
            this.battleEngine.render();
          }

          if (this.state === 'transition') {
            this.transition.render(ctx);
          }
        }

        loop(now) {
          const dt = Math.min(34, now - this.lastTime);
          this.lastTime = now;
          this.update(dt);
          this.render();
          this.input.endFrame();
          requestAnimationFrame(this.loop.bind(this));
        }
      }

      const game = new Game();
      game.init();
    })();
  </script>
</body>
</html>
"}

